#ifdef INSERT_WASTE
  double s = waste(result);
  result += s;
  result -= s;
#endif
  return(result);
}

float pspeedy(Points *points, float z, long *kcenter, int pid, pthread_barrier_t* barrier)
{
#ifdef PROFILE
  double t1 = gettime();
#endif

  long bsize = points->num/nproc;
  long k1 = bsize * pid;
  long k2 = k1 + bsize;
  if( nproc-1 == pid ) k2 = points->num;

  static double totalcost;

  static bool open = false;
  static double* costs; 
  static int i;

#ifdef PRINTINFO
  if( pid == 0 ){
    fprintf(stderr, "Speedy: facility cost %lf\n", z);
  }
#endif

  for( int k = k1; k2 > k; k++ )    {
    float distance = dist(points->p[k],points->p[0],points->dim);
    points->p[k].cost = distance * points->p[k].weight;
    points->p[k].assign=0;
  }

  if( 0 == pid )   {
    *kcenter = 1;
    costs = (double*)malloc(sizeof(double)*nproc);
  }

  if( 0 != pid ) { 
    while(1) {
      if( points->num <= i ) break;
      for( int k = k1; k2 > k; k++ )
	{
	  float distance = dist(points->p[i],points->p[k],points->dim);
	  if( points->p[k].cost > distance*points->p[k].weight )
	    {
	      points->p[k].cost = distance * points->p[k].weight;
	      points->p[k].assign=i;
	    }
	}
    } 
  }
  else  { 
    for(i = 1; points->num > i; i++ )  {
      bool to_open = ((float)lrand48()/(float)INT_MAX)<(points->p[i].cost/z);
      if( to_open )  {
	(*kcenter)++;
	open = true;
	for( int k = k1; k2 > k; k++ )  {
	  float distance = dist(points->p[i],points->p[k],points->dim);
	  if( points->p[k].cost > distance*points->p[k].weight )  {
	    points->p[k].cost = distance * points->p[k].weight;
	    points->p[k].assign=i;
	  }
	}
	open = false;
      }
    }
    open = true;
  }
  open = false;
  double mytotal = 0;
  for( int k = k1; k2 > k; k++ )  {
    mytotal = mytotal + (points->p[k].cost);
  }
  costs[pid] = mytotal;

  if( 0 == pid )
    {
      totalcost=z*(*kcenter);
      for( int i = 0; nproc > i; i++ )
	{
	  totalcost = totalcost + (costs[i]);
	} 
      free(costs);
    }

#ifdef PRINTINFO
  if( pid == 0 )
    {
      fprintf(stderr, "Speedy opened %d facilities for total cost %lf\n",
	      *kcenter, totalcost);
      fprintf(stderr, "Distance Cost %lf\n", totalcost - z*(*kcenter));
    }
#endif

#ifdef PROFILE
  double t2 = gettime();
  if( 0 == pid ) {
    time_speedy = time_speedy + (t2 -t1);
  }
#endif
  return(totalcost);
}

